import React, { useState, useRef } from 'react';
import { QRCodeSVG } from 'qrcode.react';
import './App.css';

const DRIVE_LINK = 'https://drive.google.com/drive/folders/1N8xtmD_NZQXi8L5qyEnAgI0QEyaWvztp?usp=sharing';

// ---- İllüstrasyon: Davetiyedeki yüzük + çiçek ----
function Illustration() {
  return (
    <svg className="illustration" viewBox="0 0 200 115" fill="none" xmlns="http://www.w3.org/2000/svg">
      {/* Sol çiçek demeti */}
      <g stroke="#3a3a3a" strokeLinecap="round">
        <path d="M38 95 Q34 80 31 66" strokeWidth="0.8"/>
        <path d="M38 95 Q42 79 45 65" strokeWidth="0.8"/>
        <path d="M38 95 Q38 78 38 62" strokeWidth="0.8"/>
        <path d="M34 74 Q27 70 25 63 Q32 64 34 74" fill="#d4c9b8" strokeWidth="0.6"/>
        <path d="M42 72 Q49 68 51 61 Q44 62 42 72" fill="#d4c9b8" strokeWidth="0.6"/>
        <circle cx="31" cy="63" r="4.5" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="31" cy="63" r="1.6" fill="#c8b49a" stroke="none"/>
        <circle cx="45" cy="62" r="3.8" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="45" cy="62" r="1.4" fill="#c8b49a" stroke="none"/>
        <circle cx="38" cy="58" r="5.5" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="38" cy="58" r="2" fill="#c8b49a" stroke="none"/>
        <ellipse cx="26" cy="57" rx="2" ry="3.2" strokeWidth="0.6" fill="#ece5db"/>
        <ellipse cx="50" cy="55" rx="1.8" ry="3" strokeWidth="0.6" fill="#ece5db"/>
      </g>
      {/* Sağ çiçek demeti */}
      <g stroke="#3a3a3a" strokeLinecap="round">
        <path d="M162 95 Q158 80 155 66" strokeWidth="0.8"/>
        <path d="M162 95 Q166 79 169 65" strokeWidth="0.8"/>
        <path d="M162 95 Q162 78 162 62" strokeWidth="0.8"/>
        <path d="M158 74 Q151 70 149 63 Q156 64 158 74" fill="#d4c9b8" strokeWidth="0.6"/>
        <path d="M166 72 Q173 68 175 61 Q168 62 166 72" fill="#d4c9b8" strokeWidth="0.6"/>
        <circle cx="155" cy="63" r="4.5" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="155" cy="63" r="1.6" fill="#c8b49a" stroke="none"/>
        <circle cx="169" cy="62" r="3.8" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="169" cy="62" r="1.4" fill="#c8b49a" stroke="none"/>
        <circle cx="162" cy="58" r="5.5" strokeWidth="0.8" fill="#f5f2ee"/>
        <circle cx="162" cy="58" r="2" fill="#c8b49a" stroke="none"/>
        <ellipse cx="150" cy="57" rx="2" ry="3.2" strokeWidth="0.6" fill="#ece5db"/>
        <ellipse cx="174" cy="55" rx="1.8" ry="3" strokeWidth="0.6" fill="#ece5db"/>
      </g>
      {/* Çift yüzük */}
      <circle cx="88" cy="80" r="19" stroke="#3a3a3a" strokeWidth="1.3" fill="none"/>
      <circle cx="112" cy="80" r="19" stroke="#3a3a3a" strokeWidth="1.3" fill="none"/>
      {/* Taş */}
      <g transform="translate(100,56)">
        <polygon points="0,-8 7,-2 5,5 -5,5 -7,-2" stroke="#3a3a3a" strokeWidth="0.8" fill="#faf8f5"/>
        <line x1="0" y1="-8" x2="0" y2="5" stroke="#c8b49a" strokeWidth="0.5"/>
        <line x1="-7" y1="-2" x2="7" y2="-2" stroke="#c8b49a" strokeWidth="0.5"/>
        <line x1="-5" y1="5" x2="5" y2="5" stroke="#3a3a3a" strokeWidth="0.8"/>
      </g>
      {/* Alt dekor */}
      <path d="M55 100 Q100 108 145 100" stroke="#3a3a3a" strokeWidth="0.5" fill="none" opacity="0.3" strokeLinecap="round"/>
      <g stroke="#3a3a3a" strokeWidth="0.5" opacity="0.4" strokeLinecap="round">
        <path d="M58 103 Q63 99 68 103"/>
        <path d="M132 103 Q137 99 142 103"/>
      </g>
    </svg>
  );
}

export default function App() {
  const [dragging, setDragging] = useState(false);
  const dropRef = useRef(null);

  const handleDragOver = (e) => { e.preventDefault(); setDragging(true); };
  const handleDragLeave = () => setDragging(false);
  const handleDrop = (e) => { e.preventDefault(); setDragging(false); };

  const handleUploadClick = () => {
    window.open(DRIVE_LINK, '_blank');
  };

  return (
    <div className="page">
      <div className="container">
        <Illustration />

